Here's a complete example with both `DataRow` and `DynamicData` approaches:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace PriceCalculator.Tests;

[TestClass]
public class PriceCalculatorTests
{
    private Calculator.PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new Calculator.PriceCalculator();

    // --- DataRow: best for simple inline values ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double price, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)price);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.10, 90.00, DisplayName = "10% off 100")]
    [DataRow(250.00, 0.25, 187.50, DisplayName = "25% off 250")]
    [DataRow(50.00, 0.00, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 1.00, 0.00, DisplayName = "100% discount")]
    public void ApplyDiscount_ReturnsExpected(double total, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)total, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: best for complex objects or computed test cases ---

    [TestMethod]
    [DynamicData(nameof(BulkDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_BulkScenarios(decimal total, decimal discount, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(total, discount);
        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    private static IEnumerable<object[]> BulkDiscountCases()
    {
        yield return [1000m, 0.05m, 950.00m, "Small bulk order"];
        yield return [5000m, 0.15m, 4250.00m, "Medium bulk order"];
        yield return [10000m, 0.20m, 8000.00m, "Large bulk order"];
    }

    // DynamicData from a property
    [TestMethod]
    [DynamicData(nameof(EdgeCases))]
    public void CalculateTotal_EdgeCases(int quantity, decimal price, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, price);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> EdgeCases => new[]
    {
        new object[] { int.MaxValue, 0m, 0m },
        new object[] { 1, decimal.MaxValue, decimal.MaxValue },
        new object[] { 1, 0.001m, 0.001m },
    };

    // --- Negative tests with DataRow ---

    [TestMethod]
    [DataRow(-1, 10.00)]
    [DataRow(1, -5.00)]
    public void CalculateTotal_InvalidInputs_Throws(int quantity, double price)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(quantity, (decimal)price));
    }

    [TestMethod]
    [DataRow(100.00, -0.10)]
    [DataRow(100.00, 1.50)]
    public void ApplyDiscount_InvalidDiscount_Throws(double total, double discount)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)total, (decimal)discount));
    }
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|-------------|
| `[DataRow]` | Simple primitive inputs; inline & readable |
| `[DynamicData]` (method) | Complex objects, computed cases, or `decimal` literals |
| `[DynamicData]` (property) | Reusable data shared across tests |
| `DisplayName` | Clarify intent in test explorer |

**Notes:**
- `DataRow` doesn't support `decimal` literals directly — use `double` and cast, or prefer `DynamicData` for precise decimal values.
- Use `[TestInitialize]` over constructors for setup.
- One logical assertion per test method keeps failures clear.
